-- 6. Medway × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'medway',
  'Social media in Medway operates at a scale that reflects its 280,000 population. Facebook community groups for Rochester, Chatham, Gillingham, and Strood each have thousands of active members posting daily recommendations requests. Instagram drives footfall to Rochester High Street''s independent shops and the Chatham Maritime restaurants. The University of Kent and Canterbury Christ Church at Medway bring a student demographic that lives on social media and expects every business to have an active, polished presence. Yet the majority of Medway businesses either have no social media at all or maintain dormant profiles with outdated information and no consistent posting. In a conurbation this large, where word-of-mouth recommendations happen online rather than over garden fences, a properly branded social media presence is essential infrastructure, not an optional extra.',
  'Medway''s social media landscape is driven by hyperlocal community groups that mirror the five-town structure. Facebook groups for Rochester residents, Chatham community, Gillingham locals, and Strood neighbours each operate as independent recommendation engines. Instagram is particularly strong in Rochester''s creative and hospitality sector. TikTok is gaining traction with the university student demographic. Google reviews heavily influence search rankings across the conurbation. LinkedIn serves the professional community on Medway City Estate and in Chatham Maritime commercial spaces.',
  'Social media maturity across Medway is inconsistent. Rochester''s creative quarter and hospitality businesses generally maintain active Instagram and Facebook profiles. Chatham Maritime''s newer businesses tend to be more social media aware. But across Gillingham, Strood, and the industrial estates, the vast majority of businesses have minimal or dormant social media presence. Very few Medway businesses maintain consistent branding across all platforms.',
  'We set up social media for Medway businesses based on which of the five towns your customers live in and where they spend time online. Trades serving Gillingham and Chatham get Facebook profiles optimised for community group engagement. Rochester hospitality businesses get Instagram-first strategies. Engineering firms on Medway City Estate get LinkedIn company pages. Student-facing businesses get TikTok and Instagram setups. Every profile is branded consistently and optimised for local discovery.',
  '{"population": 280000, "growth": "Large hyperlocal community groups across five towns", "business_districts": ["Rochester creative quarter", "Chatham Maritime", "Gillingham", "Medway City Estate", "Universities at Medway"], "key_fact": "Separate community Facebook groups for each town act as independent recommendation engines"}',
  '[{"title": "Missing from Medway''s town-specific recommendation groups", "description": "When a Gillingham resident posts asking for a reliable electrician or a Rochester local requests a restaurant recommendation, your business is invisible if it has no social media presence. Each Medway town has its own active community group generating genuine customer referrals daily, and businesses without profiles cannot participate in any of them."}, {"title": "Dormant profiles damaging trust in a large market", "description": "A Medway business with a Facebook page last updated a year ago sends a worse signal than having no page at all. With 280,000 potential customers checking social media to verify businesses before making contact, a dormant or poorly maintained profile suggests your business may have closed or does not care about its reputation."}, {"title": "Inconsistent presence across platforms and Medway towns", "description": "Different logos on Facebook, Instagram, and Google Business Profile. Active on one platform, silent on another. Medway businesses with inconsistent social media presence confuse potential customers and miss opportunities across the different platforms favoured by each town''s demographic."}]',
  '[{"title": "Town-specific social media profiles for Medway businesses", "description": "We build and optimise your social media profiles for engagement in each relevant Medway town''s community groups. Professional branding, complete service information, and proper categorisation ensure your profiles are ready to convert recommendation requests in Rochester, Chatham, Gillingham, Strood, and Rainham groups."}, {"title": "Platform-specific setup for each Medway audience", "description": "Trades get Facebook-first setups for community group engagement across Medway''s residential towns. Rochester hospitality gets Instagram profiles with professional imagery templates. Medway City Estate firms get LinkedIn pages built for B2B credibility. Student-facing businesses get TikTok and Instagram presence. Every platform is chosen for your specific Medway audience."}, {"title": "Consistent cross-platform brand presence across the conurbation", "description": "Same logo, same colours, same contact details, same messaging across every platform. We set up and brand your Facebook, Instagram, Google Business Profile, and LinkedIn with identical visual identity and accurate information, creating the consistent professional impression that builds recognition across Medway''s five towns."}]',
  '[{"question": "Which social media platforms should my Medway business be on?", "answer": "It depends entirely on your customers and which Medway towns you serve. For trades targeting Gillingham and Chatham, Facebook is essential for community groups. For Rochester hospitality, Instagram drives footfall. For Medway City Estate B2B firms, LinkedIn builds credibility. For student-facing businesses, TikTok and Instagram reach the university demographic."}, {"question": "Do you manage social media ongoing or just set it up?", "answer": "This service focuses on professional setup: creating, branding, and optimising your profiles so they are ready to generate business across Medway. We also provide content templates and a posting guide so you can maintain your presence independently. Ongoing management is available as a separate service."}, {"question": "How important are Google reviews for Medway businesses?", "answer": "Extremely important. With 280,000 residents choosing between hundreds of competing businesses, Google reviews are often the deciding factor. We set up your Google Business Profile with optimised categories covering all five Medway towns and implement a review generation strategy that makes it easy for satisfied customers to leave feedback."}, {"question": "Can you help me engage with community groups for specific Medway towns?", "answer": "We set up your profiles so they are ready for engagement in each town''s community groups, including professional branding, complete service information, and portfolio images. Direct group engagement should come from you personally, as authenticity is key in Medway''s tight-knit community groups."}]',
  'trust'
)
