-- 7. Medway × Digital Marketing
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'digital-marketing',
  'medway',
  'Medway''s 280,000 residents represent the largest concentrated customer base in Kent outside of Maidstone, yet most local businesses are failing to reach them through digital channels. The conurbation''s five towns generate distinct search patterns, social media behaviours, and purchasing habits that require a targeted approach, not the broad-brush campaigns that waste budget across audiences who will never become customers. A Gillingham plumber does not need to advertise in Rochester. A Rochester fine dining restaurant does not need to target Medway City Estate. Yet most Medway businesses that do advertise digitally run untargeted campaigns that scatter budget across the entire region. Our digital marketing campaigns are built specifically for Medway''s multi-town geography, using paid search, social advertising, and local SEO to put your business in front of the right customers in the right town at the moment they are ready to buy.',
  'Medway''s digital marketing landscape is shaped by its multi-town structure and large, diverse population. Rochester generates tourist and heritage-oriented search intent. Chatham drives high-volume retail and residential service searches. Gillingham produces consistent trades and food delivery demand. Strood captures M2 commuter traffic. Medway City Estate creates B2B search and advertising opportunities. The university campus generates seasonal student-oriented demand. Each segment requires different targeting, messaging, and platform selection.',
  'Digital advertising competition in Medway is substantial due to the population size. Google Ads costs for service keywords are higher than smaller Kent towns, and Facebook advertising is crowded. National brands and chains advertise heavily across the conurbation. However, very few local Medway businesses use precise geographic targeting within the conurbation, meaning campaigns that differentiate between towns and neighbourhoods can achieve strong returns by reaching the right people rather than the most people.',
  'We build Medway digital marketing campaigns around precise town-level targeting. Paid search campaigns target specific postcode areas within Rochester, Chatham, Gillingham, Strood, and Rainham separately. Social media advertising reaches residents by town, interest, and demographic. Retargeting campaigns re-engage visitors who browsed your website but did not convert. Every campaign is measured against actual leads and revenue generated, not impressions or clicks.',
  '{"population": 280000, "growth": "Kent''s largest conurbation outside Maidstone", "business_districts": ["Rochester", "Chatham", "Gillingham", "Strood", "Medway City Estate"], "key_fact": "Five-town structure requires town-level targeting for efficient advertising spend"}',
  '[{"title": "Scattergun advertising wasting budget across Medway", "description": "Medway businesses running broad campaigns that target the entire conurbation waste significant budget reaching people in towns they do not serve or demographics that will never convert. A Strood takeaway advertising to Rochester residents or a Rochester jeweller targeting Gillingham postcodes throws money away. Precision targeting is essential in a multi-town market."}, {"title": "National brands outspending local Medway businesses online", "description": "National chains and franchise businesses invest heavily in digital advertising across Medway, pushing local businesses down in paid search results and filling social media feeds. Without strategic campaigns that leverage local knowledge and precise targeting, independent Medway businesses cannot compete on budget alone."}, {"title": "No measurement of which marketing channels work in Medway", "description": "Most Medway businesses cannot identify which marketing activities generate their leads. They run ads, post on social media, and distribute flyers, but have no tracking to determine which channels produce paying customers. This makes it impossible to invest intelligently in a market as large and diverse as Medway."}]',
  '[{"title": "Town-level digital campaigns across the Medway conurbation", "description": "We build separate campaign structures for each Medway town you serve. A Rochester campaign targets heritage visitors and affluent locals. A Gillingham campaign reaches residential homeowners. A Chatham campaign captures the Pentagon Centre catchment and Chatham Maritime professionals. Each campaign is optimised independently for maximum return."}, {"title": "Precision-targeted paid search for Medway service keywords", "description": "We build Google Ads campaigns targeting high-intent keywords within specific Medway town postcodes. Every click comes from someone actively searching for your service in your area. We optimise bids by time of day, device, and town to maximise your return from Medway''s large but geographically segmented search market."}, {"title": "Full-funnel tracking from Medway ad click to paying customer", "description": "Every campaign we run includes complete conversion tracking. You know exactly which Medway towns, keywords, ads, and platforms generate phone calls, form submissions, and revenue. Monthly reporting shows your cost per lead, cost per customer, and return on investment broken down by town."}]',
  '[{"question": "What digital marketing budget do Medway businesses typically need?", "answer": "Given Medway''s large population, most service businesses see strong results starting from seven hundred and fifty to fifteen hundred pounds per month in advertising spend, plus management fees. Businesses serving all five towns may need higher budgets. We provide forecasts based on actual Medway keyword costs and town-level competition."}, {"question": "Should I target all five Medway towns or focus on specific areas?", "answer": "This depends on your business model and capacity. A plumber covering the whole conurbation benefits from all-town campaigns. A Rochester restaurant only needs to target the immediate area. We recommend starting with the towns that offer the best return and expanding as results justify increased investment."}, {"question": "How quickly will I see results from digital marketing in Medway?", "answer": "Paid advertising generates leads from day one. Google Ads campaigns typically produce qualified enquiries within the first week. Social media advertising builds momentum over two to four weeks. We provide weekly reporting from launch so you can see exactly what is happening across each Medway town."}, {"question": "Can you target specific areas like Chatham Maritime or Medway City Estate?", "answer": "Yes. Geo-targeting at postcode and area level is central to our approach. We can target specific developments, industrial estates, and neighbourhoods within the Medway conurbation. This precision ensures your budget reaches only the people who can actually become your customers."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
